import './Link.scss';

import { classNames } from ':helpers/classnames';
import type { ReactElement } from 'react';
import React, { forwardRef } from 'react';

import type { LinkProps } from './Link.types';

const renderContent = (
	startIcon: React.ReactNode,
	children: React.ReactNode,
	endIcon: React.ReactNode,
): React.ReactNode => (
	<>
		{startIcon && (
			<span className="dsb_link-start-icon" aria-hidden="true">
				{startIcon}
			</span>
		)}
		<span className="dsb_link-text">{children}</span>
		{endIcon && (
			<span className="dsb_link-end-icon" aria-hidden="true">
				{endIcon}
			</span>
		)}
	</>
);

export const Link = forwardRef<HTMLAnchorElement | HTMLButtonElement | HTMLElement, LinkProps>(
	(
		{
			href,
			component,
			size = 'medium',
			startIcon,
			endIcon,
			disabled = false,
			visited,
			children,
			className,
			dataTestId = 'Link',
			target,
			rel,
			download,
			onClick,
			onFocus,
			onBlur,
			...rest
		},
		ref,
	) => {
		const content = renderContent(startIcon, children, endIcon);

		const linkClassNames = classNames(
			'dsb_link',
			`dsb_link__${size}`,
			{
				dsb_link__disabled: disabled,
				dsb_link__visited: visited,
				'dsb_link__with-start-icon': !!startIcon,
				'dsb_link__with-end-icon': !!endIcon,
			},
			className,
		);

		const resolvedRel = target === '_blank' ? [rel, 'noopener', 'noreferrer'].filter(Boolean).join(' ') : rel;

		// SPA: component (React Router, Next.js Link и т.п.)
		if (component && !disabled) {
			return React.cloneElement(component as ReactElement<any>, {
				className: classNames(linkClassNames, (component.props as { className?: string }).className),
				children: content,
				ref,
				'data-testid': dataTestId,
				onClick,
				onFocus,
				onBlur,
				...rest,
			});
		}

		// disabled: всегда span (для href, component или button)
		if (disabled) {
			return (
				<span
					{...rest}
					className={linkClassNames}
					ref={ref as React.Ref<HTMLSpanElement>}
					role="link"
					aria-disabled="true"
					data-testid={dataTestId}
				>
					{content}
				</span>
			);
		}

		// Нативная ссылка
		if (href) {
			return (
				<a
					{...rest}
					href={href}
					target={target}
					rel={resolvedRel}
					download={download}
					className={linkClassNames}
					ref={ref as React.Ref<HTMLAnchorElement>}
					onClick={onClick}
					onFocus={onFocus}
					onBlur={onBlur}
					data-testid={dataTestId}
				>
					{content}
				</a>
			);
		}

		// Действие без навигации (Copy, Collapse) — button
		return (
			<button
				{...(rest as React.ButtonHTMLAttributes<HTMLButtonElement>)}
				type="button"
				role="link"
				className={linkClassNames}
				ref={ref as React.Ref<HTMLButtonElement>}
				onClick={onClick}
				onFocus={onFocus}
				onBlur={onBlur}
				data-testid={dataTestId}
			>
				{content}
			</button>
		);
	},
);

Link.displayName = 'Link';
